solution: String defangIPaddr(String address) {
    String output = "";
    for (int i = 0; i < address.length(); i++) {
        char c = address.charAt(i);
        if (Character.isDigit(c)) {
            output += "[" + c + "]";
        } else {
            output += c;
        }
    }
    return output;
}

